      "path": "src/modules/comments/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const { createComment, getComments } = require('./service');

router.post('/', (req, res) => {
  const { message } = req.body;
  if (!message) {
    return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Message is required' } });
  }
  createComment(message)
    .then(comment => res.status(201).json(comment))
    .catch(error => res.status(500).json({ error: { code: 'INTERNAL_SERVER_ERROR', message: error.message } }));
});

router.get('/', (req, res) => {
  getComments()
    .then(comments => res.json(comments))
    .catch(error => res.status(500).json({ error: { code: 'INTERNAL_SERVER_ERROR', message: error.message } }));
});

module.exports = router;"
