    return res.status(400).json({ error: { code: 'BAD_REQUEST', message: 'Project ID, title, and description are required' } });
  }
  createTask(projectId, title, description)
    .then(task => res.status(201).json(task))
    .catch(error => res.status(500).json({ error: { code: 'INTERNAL_SERVER_ERROR', message: error.message } }));
});

router.get('/:projectId', (req, res) => {
  const { projectId } = req.params;
  getTasks(projectId)
    .then(tasks => res.json(tasks))
    .catch(error => res.status(500).json({ error: { code: 'INTERNAL_SERVER_ERROR', message: error.message } }));
});

