      "content": "const { randomUUID } = require('../../lib/id');

const tasks = [];

const createTask = (projectId, title, description) => {
  const task = { id: randomUUID(), projectId, title, description, status: 'todo', createdAt: new Date() };
  tasks.push(task);
  return Promise.resolve(task);
};

const getTasks = (projectId) => {
  const task = tasks.filter(t => t.projectId === projectId);
  return Promise.resolve(task);
};

